{"content": """"
搜索工具
使用 DuckDuckGo API
"""
import aiohttp
import json
from bot.tools.base import BaseTool, ToolResult
from bot.logger import setup_logger

logger = setup_logger()


class SearchTool(BaseTool):
    """网络搜索工具"""

    @property
    def name(self) -> str:
        return "search"

    @property
    def description(self) -> str:
        return "搜索互联网获取信息。使用此工具来回答需要最新信息或实时数据的问题。"

    @property
    def parameters(self) -> dict:
        return {
            "type": "object",
            "properties": {
                "query": {
                    "type": "string",
                    "description": "搜索关键词"
                },
                "max_results": {
                    "type": "integer",
                    "description": "返回结果数量，默认3",
                    "default": 3
                }
            },
            "required": ["query"]
        }

    async def execute(self, **kwargs) -> ToolResult:
        query = kwargs.get("query", "")
        max_results = kwargs.get("max_results", 3)

        if not query:
            return ToolResult(success=False, result=None, error="搜索关键词不能为空")

        try:
            # 使用 DuckDuckGo HTML API
            url = "https://html.duckduckgo.com/html/"
            data = {"q": query, "b": max_results}

            async with aiohttp.ClientSession() as session:
                async with session.post(url, data=data, timeout=aiohttp.ClientTimeout(total=15)) as response:
                    if response.status == 200:
                        html = await response.text()
                        results = self._parse_results(html, max_results)

                        logger.info(f"搜索成功: {query}, 找到 {len(results)} 个结果")
                        return ToolResult(success=True, result=results)
                    else:
                        return ToolResult(success=False, result=None, error=f"API 返回错误: {response.status}")

        except aiohttp.ClientError as e:
            logger.error(f"搜索网络错误: {e}")
            return ToolResult(success=False, result=None, error=f"网络错误: {str(e)}")
        except Exception as e:
            logger.error(f"搜索未知错误: {e}")
            return ToolResult(success=False, result=None, error=str(e))

    def _parse_results(self, html: str, max_results: int) -> list:
        """解析搜索结果 HTML"""
        results = []
        import re

        # 提取搜索结果
        result_pattern = r'<a class="result__a" href="[^"]*"[^>]*>([^<]*)</a>.*?<a class="result__snippet"[^>]*>([^<]*)</a>'
        matches = re.findall(result_pattern, html, re.DOTALL)

        for i, (title, snippet) in enumerate(matches[:max_results]):
            # 清理 HTML 实体
            title = title.replace('&', '&').replace('<', '<').replace('>', '>')
            snippet = snippet.replace('&', '&').replace('<', '<').replace('>', '>').replace('<br>', ' ').strip()
            results.append({
                "序号": i + 1,
                "标题": title.strip(),
                "摘要": snippet.strip()[:200]
            })

        if not results:
            # 尝试备用解析
            title_pattern = r'<a class="result__a"[^>]*>([^<]*)</a>'
            titles = re.findall(title_pattern, html)[:max_results]
            for i, title in enumerate(titles):
                title = title.replace('&', '&')
                results.append({
                    "序号": i + 1,
                    "标题": title.strip(),
                    "摘要": "（请访问链接查看详情）"
                })

        return results", "path": "F:\claw\telegram-bot-framework\bot\tools\search.py"}

{"content": """"
计算器工具
安全的数学表达式计算
"""
import ast
import operator
from bot.tools.base import BaseTool, ToolResult
from bot.logger import setup_logger

logger = setup_logger()

# 支持的运算符
operators = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.Pow: operator.pow,
    ast.Mod: operator.mod,
    ast.FloorDiv: operator.floordiv,
}

# 支持的函数
functions = {
    'abs': abs,
    'round': round,
    'min': min,
    'max': max,
    'pow': pow,
    'sqrt': lambda x: x ** 0.5,
    'sin': lambda x: __import__('math').sin(__import__('math').radians(x)),
    'cos': lambda x: __import__('math').cos(__import__('math').radians(x)),
    'tan': lambda x: __import__('math').tan(__import__('math').radians(x)),
    'log': __import__('math').log,
    'log10': __import__('math').log10,
    'pi': __import__('math').pi,
    'e': __import__('math').e,
}


class CalculatorTool(BaseTool):
    """计算器工具"""

    @property
    def name(self) -> str:
        return "calculator"

    @property
    def description(self) -> str:
        return "安全地执行数学计算。支持加减乘除、幂运算、三角函数、对数等。使用此工具来计算数学表达式。"

    @property
    def parameters(self) -> dict:
        return {
            "type": "object",
            "properties": {
                "expression": {
                    "type": "string",
                    "description": "数学表达式，例如：2 + 2, sqrt(16) * 3, sin(30)"
                }
            },
            "required": ["expression"]
        }

    async def execute(self, **kwargs) -> ToolResult:
        expression = kwargs.get("expression", "")

        if not expression:
            return ToolResult(success=False, result=None, error="表达式不能为空")

        try:
            result = self._safe_eval(expression)
            logger.info(f"计算成功: {expression} = {result}")
            return ToolResult(success=True, result=str(result))
        except Exception as e:
            logger.error(f"计算错误: {e}")
            return ToolResult(success=False, result=None, error=f"计算错误: {str(e)}")

    def _safe_eval(self, expr: str) -> float:
        """安全地计算数学表达式"""
        # 清理表达式
        expr = expr.strip().replace('×', '*').replace('÷', '/').replace('^', '**')

        # 解析 AST
        node = ast.parse(expr, mode='eval')
        return self._eval_node(node.body)

    def _eval_node(self, node):
        """递归计算 AST 节点"""
        if isinstance(node, ast.Num):  # 数字
            return node.n
        elif isinstance(node, ast.BinOp):  # 二元运算
            left = self._eval_node(node.left)
            right = self._eval_node(node.right)
            op_type = type(node.op)
            if op_type in operators:
                return operators[op_type](left, right)
            raise ValueError(f"不支持的运算符: {op_type.__name__}")
        elif isinstance(node, ast.UnaryOp):  # 一元运算
            if isinstance(node.op, ast.USub):
                return -self._eval_node(node.operand)
            elif isinstance(node.op, ast.UAdd):
                return self._eval_node(node.operand)
        elif isinstance(node, ast.Call):  # 函数调用
            func_name = node.func.id if isinstance(node.func, ast.Name) else None
            if func_name in functions:
                args = [self._eval_node(arg) for arg in node.args]
                return functions[func_name](*args)
            raise ValueError(f"不支持的函数: {func_name}")
        elif isinstance(node, ast.Name):  # 变量/常量
            if node.id in functions:
                return functions[node.id]
            raise ValueError(f"未定义的变量: {node.id}")
        elif isinstance(node, ast.Constant):  # 常量 (Python 3.8+)
            return node.value
        else:
            raise ValueError(f"不支持的表达式类型: {type(node).__name__}")", "path": "F:\claw\telegram-bot-framework\bot\tools\calculator.py"}

{"content": """"
工作流定义和执行器
"""
import json
import asyncio
import aiohttp
from enum import Enum
from typing import Dict, List, Any, Optional, Callable
from dataclasses import dataclass, field
from datetime import datetime
from bot.logger import setup_logger

logger = setup_logger()


class ActionType(Enum):
    """动作类型"""
    SEND_MESSAGE = "send_message"
    CALL_API = "call_api"
    SEND_NOTIFICATION = "send_notification"
    EXECUTE_SCRIPT = "execute_script"
    CONDITION = "condition"


@dataclass
class Action:
    """动作定义"""
    action_type: ActionType
    params: Dict[str, Any]
    condition: Optional[str] = None  # 条件表达式
    next_actions: List["Action"] = field(default_factory=list)


@dataclass
class Workflow:
    """工作流定义"""
    id: str
    name: str
    description: str = ""
    enabled: bool = True
    trigger_type: str = "manual"  # manual, cron, interval, webhook
    trigger_config: Dict[str, Any] = field(default_factory=dict)
    actions: List[Action] = field(default_factory=list)
    created_at: datetime = field(default_factory=datetime.now)
    last_run: Optional[datetime] = None

    def to_dict(self) -> Dict:
        """转换为字典"""
        return {
            "id": self.id,
            "name": self.name,
            "description": self.description,
            "enabled": self.enabled,
            "trigger_type": self.trigger_type,
            "trigger_config": self.trigger_config,
            "created_at": self.created_at.isoformat(),
            "last_run": self.last_run.isoformat() if self.last_run else None
        }

    @classmethod
    def from_dict(cls, data: Dict) -> "Workflow":
        """从字典创建"""
        wf = cls(
            id=data["id"],
            name=data["name"],
            description=data.get("description", ""),
            enabled=data.get("enabled", True),
            trigger_type=data.get("trigger_type", "manual"),
            trigger_config=data.get("trigger_config", {})
        )
        if data.get("created_at"):
            wf.created_at = datetime.fromisoformat(data["created_at"])
        if data.get("last_run"):
            wf.last_run = datetime.fromisoformat(data["last_run"])
        return wf


class WorkflowExecutor:
    """工作流执行器"""

    def __init__(self, bot=None):
        self.bot = bot
        self.workflows: Dict[str, Workflow] = {}
        self._running = False

    def register_workflow(self, workflow: Workflow):
        """注册工作流"""
        self.workflows[workflow.id] = workflow
        logger.info(f"注册工作流: {workflow.name} ({workflow.id})")

    def unregister_workflow(self, workflow_id: str) -> bool:
        """注销工作流"""
        if workflow_id in self.workflows:
            del self.workflows[workflow_id]
            return True
        return False

    def get_workflow(self, workflow_id: str) -> Optional[Workflow]:
        """获取工作流"""
        return self.workflows.get(workflow_id)

    def list_workflows(self) -> List[Dict]:
        """列出所有工作流"""
        return [wf.to_dict() for wf in self.workflows.values()]

    async def execute_workflow(self, workflow_id: str, context: Dict = None) -> Dict:
        """执行工作流"""
        workflow = self.get_workflow(workflow_id)
        if not workflow:
            return {"success": False, "error": f"工作流不存在: {workflow_id}"}

        if not workflow.enabled:
            return {"success": False, "error": "工作流已禁用"}

        logger.info(f"执行工作流: {workflow.name}")
        context = context or {}

        try:
            result = await self._execute_actions(workflow.actions, context)
            workflow.last_run = datetime.now()
            return {"success": True, "result": result}
        except Exception as e:
            logger.error(f"工作流执行错误: {e}")
            return {"success": False, "error": str(e)}

    async def _execute_actions(self, actions: List[Action], context: Dict) -> Any:
        """执行动作列表"""
        results = []
        for action in actions:
            result = await self._execute_action(action, context)
            results.append(result)

            # 检查条件
            if action.condition:
                if not self._evaluate_condition(action.condition, context):
                    continue

            # 如果是条件动作，处理分支
            if action.action_type == ActionType.CONDITION:
                if result.get("success"):
                    return await self._execute_actions(action.next_actions, context)

        return results[-1] if results else None

    async def _execute_action(self, action: Action, context: Dict) -> Dict:
        """执行单个动作"""
        logger.debug(f"执行动作: {action.action_type.value}")

        try:
            if action.action_type == ActionType.SEND_MESSAGE:
                return await self._action_send_message(action.params, context)
            elif action.action_type == ActionType.CALL_API:
                return await self._action_call_api(action.params, context)
            elif action.action_type == ActionType.SEND_NOTIFICATION:
                return await self._action_send_notification(action.params, context)
